export interface Subtopic {
  name: string;
  description?: string;
}

export interface MainTopic {
  title: string;
  subtopics: Subtopic[];
}

export const abstractTopicsData: MainTopic[] = [
  {
    title: `Biofabrication`,
    subtopics: [
      { name: `Biofabrication (general session)`, description: `General session on Biofabrication` },
      { name: `Biofabrication of spatial gradients and complex interfaces`, description: `Native tissue function is governed by precise spatial organization and complex matrix heterogeneity. During morphogenesis, spatial signaling cues and growth factor gradients play a critical role in regulating cell differentiation and patterning. However, replicating such hierarchical architecture remains a significant challenge. Biofabrication provides the necessary tools to bridge this gap, enabling the precise engineering of structural and biochemical gradients to recreate functional tissue interfaces. This session explores: (1) bio-inspired strategies to mimic developmental patterning, (2) spatially complex in vitro models for screening, and (3) the fabrication of multiphasic grafts for clinical repair. By bringing together experts from biomaterials, developmental biology, and tissue engineering, this session focuses on the reconstruction of hierarchical tissue transitions, including tendon-to-bone entheses, vascularized networks, and osteochondral interfaces. Collectively, these presentations will demonstrate that recapitulating native spatial biology via biofabrication is essential for advancing the next generation of regenerative therapies from bench to the clinics.` },
      { name: `Biofabrication technologies for organoid engineering`, description: `Human organoids recapitulate multiple levels of key human organ features in vivo, holding tremendous promise for developmental biology, disease modeling, drug discovery, and regenerative medicine. A wide range of organoids has been successfully established to bridge the gap between 2D in vitro systems and animal models. Despite this progress, conventional organoids remain limited by high heterogeneity, insufficient perfusion of oxygen and nutrients, poor reproducibility, stochastic functional outcomes, and reduced physiological fidelity. To address these challenges, emerging biofabrication strategies (e.g., bioprinting, biomanufacturing,  and microphysiological systems) that integrate advanced biomaterials, microfluidics, cellular and molecular engineering tools, and AI-driven data analytics and automation have emerged for engineering more standardized and scalable organoid systems. This session will highlight cutting-edge biofabrication technologies that leverage engineering innovations to enhance the scalability and functional standardization of human organoids. By bringing together researchers from broad engineering and science fields, the session aims to catalyze interdisciplinary collaboration, showcase transformative advances, and critically discuss remaining challenges and future directions.` },
      { name: `Emerging biofabrication technologies`, description: `Emerging biofabrication technologies are rapidly reshaping the landscape of tissue engineering, regenerative medicine, and translational biomedical research. This symposium will highlight recent innovative advances in innovative biofabrication strategies such as melt electrowriting, freeform and embedded bioprinting and microchanneling approaches, which enable precise control over biomaterial architecture and cellular organization. The session will also seek to explore advances in 4D printing using stimulus-responsive materials, as well as the integration of biofabrication with microfluidic and on-chip platforms, including microphysiological systems for disease investigation, drug screening, and precision medicine applications. By bringing together researchers developing novel biofabrication technologies and advanced biomedical applications, this session aims to foster interdisciplinary discussion and highlight emerging opportunities for next-generation biofabrication platforms.` },
      { name: `Machine learning, AI and intelligent biofabrication technologies`, description: `The fusion of machine learning, AI, and intelligent systems is transforming biofabrication by enhancing accuracy, efficiency, and scalability, making these technologies essential in the field. This session will highlight AI-driven biomaterial design, such as deep learning models for predicting scaffold biocompatibility, and automated tissue engineering, including machine learning for bioprinting optimization and closed-loop systems for real-time adaptive fabrication. Additionally, it will explore robotic systems with computer vision for precision bioassembly, physics-informed neural networks for simulating dynamic cell-material interactions, and organ-on-a-chip platforms augmented by predictive analytics. By bringing together leading researchers, the session will explore cutting-edge algorithms, experimental validations, and scalable biofabrication workflows that are transforming biofabrication and regenerative medicine, while advancing our understanding of AI-driven design, automation, and predictive modeling in tissue engineering.` },
    ],
  },
  {
    title: `Bioreactors & Organs-on-Chips`,
    subtopics: [
      { name: `Bioreactors & Organs-on-Chips (general session)`, description: `General session on Bioreactors & Organs-on-Chips` },
      { name: `Advancing MPS as new approach methods (NAMs)`, description: `This session highlights the evolution of Microphysiological Systems (MPS) as transformative New Approach Methods (NAMs). We focus on bio-designed platforms—including Organ-on-Chip, Human-on-Chip, and perfused tissue constructs—that redefine the boundaries of basic research, drug discovery, and personalized medicine. By positioning these systems as essential building blocks for regenerative medicine, we aim to showcase their potential to replace traditional models with high-fidelity, human-relevant data.` },
      { name: `Dynamic biophysical modulation of tissue regeneration`, description: `Tissue engineering has traditionally relied on biochemical factors and passive spatial signaling using 3D scaffolds to guide regeneration. However, the native cellular niche is highly dynamic, where physical forces play a critical role in determining fate and function. This session explores the paradigm shift toward the use of active biophysical modulation, including electrical, mechanical, magnetic, and acoustic cues, to deliberately steer cell fate and tissue morphogenesis through precise transduction-mediated gene regulation. The session will highlight: (1) fundamental mechanisms of cellular response to active cues, (2) advanced bioreactor and organ-on-chip designs for both contact-based and remote stimulation, and (3) translational challenges in applying these forces therapeutically. Contributions from experts on these topics will collectively demonstrate how active physical modulation can drive complex tissue organization and functional maturation, particularly in cardiac, neural, and musculoskeletal tissues, more effectively than static biochemical or architectural cues alone, ultimately paving the way for superior clinical outcomes.` },
      { name: `Challenges in clinical applications of cancer organoids`, description: `3D tumor model platforms that include cell types all present in the tumor, as well as 3D organization, allow many of these models to be physiologically representative of in vivo tumor and tumor microenvironment (TME) biology. These elements not only mimic pathological and physical characteristics of tumors but importantly support preservation of mutational profiles and genetic stability of cancer cells, an essential requirement for anti-cancer treatment evaluation ex vivo. In this session, we will highlight recent developments in fabrication and testing of patient-derived cancer organoids. The session will specifically discuss barriers for clinical applications of cancer organoids including, challenges in tumor biopsy retrieval and processing, standardize fabrication methods, quality assurance, regulatory approvals, etc. As technologies continue to develop rapidly for cancer organoids fabrication, it will be essential to incorporate these potential barriers in ahead of applications in clinical and pharmaceutical settings.` },
      { name: `Emerging advances in microphysiological platforms to study disease`, description: `Human In vitro cardiac models of development, homeostasis and disease are becoming increasingly reliable for understanding disease and determining the efficacy of therapeutics. This is of immense importance as cardiotoxicity is a critical success criteria of systemic pharmaceutics and cardiac disease is one of the leading causes of death worldwide. Such models typically require the generation of cardiomyocytes from pluripotent stem cell sources, among other cell types in defined bioreactor systems. Such systems incorporate tailored strain boundaries, electric field stimulation, measurement of contractile and electrophysiology signals and flow; at macro- and micro-scale. This session captures the latest developments in capturing disease and ageing within in vitro models of cardiac tissue that are at the forefront of the field. Such models can imbibe resident and infiltrating immune cells which are only recently being captured in such models and others the crosstalk between cardiac tissues and other tissues of the body (cancer, adipose, lung etc.). This session also considers the advances in bioreactor and real-time assessment of tissues that are improving the performance of cardiac tissue models and adding greater depth to their investigations. It is the aim of this symposium that we gather as a vibrant and motivated community as engineers and scientists in engaged discussions to capture the latest advances, share, and discuss critically.` },
      { name: `Emerging in vitro and microphysiological platforms to study human–microbiome interactions`, description: `The human microbiome plays a fundamental role in health and disease, yet our ability to study host-microbiome interactions in physiologically relevant contexts remains limited. Traditional in vitro models fail to recapitulate the complexity of microbial communities and their native tissue environments, creating a critical gap between reductionist experiments and clinical reality. This session highlights emerging platforms — including hydrogel-based scaffolds, 2D culture systems, organoids, bioreactors, and organ-on-chip technologies — designed to bridge this gap by enabling more faithful recreation of the conditions that govern host-microbiome interactions. Speakers will showcase cutting-edge approaches to recreating the structural, mechanical, and biochemical cues that drive host-microbiome crosstalk across multiple organ systems. By bringing together researchers working across this spectrum of platforms, this session aims to catalyze new collaborations and accelerate the development of next-generation tools for microbiome research and therapeutic discovery.` },
      { name: `Engineering human tissues for translational impact: Advanced 3D models, microphysiological systems, and AI-enabled discovery`, description: `This session will explore emerging bioengineering strategies advancing translational research across cardiovascular, skeletal muscle, central nervous system, and gastrointestinal tissue models. The program will highlight how human-relevant, three-dimensional tissue constructs and microphysiological systems are reshaping preclinical discovery and disease modeling. Academic, industry, and regulatory leaders will discuss the integration of stem cell biology, biomaterials, bioreactor technologies, and AI-enabled analytics to enhance physiological fidelity, reproducibility, and predictive performance. Emphasis will be placed on scalable tissue platforms that support mechanistic insight, therapeutic screening, and regenerative medicine applications. By bridging engineered tissue complexity with quantitative functional readouts, these next-generation systems offer powerful tools to improve translational success and accelerate the development of safer, more effective therapies.` },
    ],
  },
  {
    title: `Cardiovascular, Angiogenesis, Blood`,
    subtopics: [
      { name: `Cardiovascular, Angiogenesis, Blood TERM (general session)`, description: `General session on Cardiovascular, Angiogenesis, Blood TERM` },
      { name: `Cardiovascular tissue engineering: From cells, ECM to AI-driven organoids`, description: `Cardiovascular tissue engineering is undergoing significant progress toward integrated, multiscale systems that recapitulate human cardiac structure, mechanics, and function. Advances in stem cell biology, extracellular matrix (ECM) engineering, and mechanobiology have enabled increasingly sophisticated cardiovascular constructs. Recently, the emergence of cardiac organoids and microphysiological systems, combined with artificial intelligence (AI)-assisted tools and platforms, are redefining how engineered cardiovascular tissues are built, optimized, and translated. This session will highlight state-of-the-art strategies that bridge biological complexity and engineering precision, spanning: a) Cellular sources and lineage specification (hiPSC-derived cardiomyocytes, endothelial cells, fibroblasts, immune cells); b) ECM composition, mechanics, and remodeling as instructive regulators of cardiac development, maturation, and disease; c) Organoid and tissue-level self-organization, including vascularized and multi-chamber cardiac systems; d) AI-enabled platforms for supporting cell differentiation and tissue formation, synthetic ECM design & discovery, cardiovascular functional phenotyping and prediction, and complex cardiovascular modeling. By integrating experimental, computational, and translational perspectives, the session will address how AI can accelerate cardiovascular tissue engineering design–build–test cycles, uncover emergent structure–function relationships in the cardiovascular systems, and improve reproducibility and scalability of cardiovascular tissues. This session will include an invited talk from one of the leaders in cardiovascular tissue engineering, specializing in stem cells, ECM, and AI-driven cardiac organoids. This session will also highlight other outstanding work in this area from TERMIS members through the submitted abstracts.` },
      { name: `Clinicians versus engineers: Exploring the use of stem cells to grow new vessels`, description: `The theme of this session will be to use a clinician's perspective to frame impacts, opportunities, or limitations for tissue engineers. The research focus will be on the use of adipose derived stem cell populations to create new blood vessels for wound healing scenarios and the an initial clinical presentation will provide examples of what clinicians really care about. Then discussion based on tissue engineering examples will be guided to emphasize impact from two different views.` },
      { name: `Functional vascularization across scales: Models, materials, and integration`, description: `This session will focus on approaches to achieve functional vascularization across length scales in engineered tissues, with an emphasis on models, materials, and integration strategies. Topics will include top-down methods such as bioprinting, molding, and microfabrication to generate perfusable vascular architectures, as well as bottom-up approaches that rely on endothelial self-organization and angiogenesis. The session will address how material design and biological cues regulate network formation, maturation, and stability, and will highlight integration of engineered and self-assembled networks to create hierarchical vascular systems capable of anastomosis with host vasculature and supporting long-term perfusion and tissue function.` },
      { name: `Lymphatic engineering and regeneration`, description: `The lymphatic system is a major circulatory system within the body, responsible for the transport of interstitial fluid, waste products, immune cells, and proteins in numerous organs and tissue types. Recently, lymphatic engineering and regeneration have been postulated as innovative therapeutic strategies for various disease phenotypes, including neurodegenerative diseases, metabolic syndrome, cardiovascular disease, and lymphedema. Yet, compared to other physiological systems, the molecular mechanisms and underlying disease pathology largely remain to be understood which has hindered advancements in therapeutic options for lymphatic disorders and regeneration. This session will bring together leading experts in the field of lymphatic biology, bioengineering, and tissue engineering to discuss the emerging topic of lymphatic engineering and regeneration. To stimulate active discussion, several submitted abstracts will also be selected for oral presentation.` },
    ],
  },
  {
    title: `Commercialization & Regulation`,
    subtopics: [
      { name: `Early-stage entrepreneurship & commercialization in regenerative medicine and tissue engineering`, description: `This session will feature founders and senior leaders of early-stage regenerative medicine and tissue engineering companies who have direct experience building and scaling their own private ventures. Each presenter will introduce their company, its mission, core technology platform, and products in development, offering insight into how scientific innovation is translated into commercial opportunity. Speakers will share candid lessons learned from launching a company in this highly technical and regulated field, including early strategic decisions, capital formation, and risk management. The session will also address critical technical, regulatory, team-building, manufacturing, reimbursement, and business development needs, as well as key resources that support successful commercialization. Emphasis will be placed on practical guidance for academic entrepreneurs, trainees, and early-career investigators considering startup formation. All presenters will participate in a moderated discussion and open audience Q&A to encourage interactive dialogue and knowledge exchange.` },
    ],
  },
  {
    title: `Dental & Craniofacial`,
    subtopics: [
      { name: `Dental & Craniofacial TERM (general session)`, description: `General session on Dental & Craniofacial TERM` },
    ],
  },
  {
    title: `Imaging and Assessment`,
    subtopics: [
      { name: `Imaging and Assessment for TERM (general session)`, description: `General session on Imaging and Assessment for TERM` },
      { name: `Quantitative non-invasive imaging for regulatory-ready engineered tissues and human-relevant models`, description: `Non-invasive imaging technologies are increasingly central to the translation of engineered tissues from bench to clinic. In parallel with the FDA Modernization Act 2.0 and evolving regulatory roadmaps encouraging reduction of animal testing through scientifically validated New Approach Methodologies, there is growing demand for quantitative, reproducible, and human-relevant assessment tools.    This session will highlight advanced structural and functional imaging strategies that generate regulatory-aligned quantitative endpoints for engineered tissues across in vitro, ex vivo, and in vivo platforms. Topics will include microCT, MRI, ultrasound and elastography, molecular imaging, and optical techniques used to assess scaffold architecture, vascularization, metabolic activity, degradation, and tissue integration. Emphasis will be placed on standardization, longitudinal monitoring, correlation with histology and mechanics, and development of imaging-derived biomarkers that support translational decision-making.    By positioning imaging as a quantitative bridge between engineered tissue platforms and regulatory evaluation, this session will advance the field toward more reproducible, mechanistically grounded, and clinically translatable outcomes.` },
    ],
  },
  {
    title: `Musculoskeletal`,
    subtopics: [
      { name: `Engineering tissue interfaces, biomolecules, and cross-talk in musculoskeletal regeneration (general session)`, description: `Engineering functional musculoskeletal tissues requires not only regenerating individual components such as bone, joints, muscle, cartilage, tendon, nerve, and vasculature, but also recreating the complex interfaces and biochemical cross-talk that integrate them. This session will highlight emerging strategies to engineer tissue interfaces and dynamic biomolecular signaling environments that facilitate regeneration through coordinate cell–cell and cell–matrix communication. Emphasis will be placed on translational approaches that bridge biology with scalable manufacturing and clinically relevant models. Together, this session will provide a comprehensive view of how engineering tissue interfaces and molecular cross-talk can drive musculoskeletal repair.` },
      { name: `3D printing advances in musculoskeletal tissue engineering`, description: `3D Printing is rapidly transforming musculoskeletal tissue engineering from simple, uniform scaffolds into patterned, functionally graded living constructs built for clinical translation. This session will spotlight emerging themes in next-generation biomaterial inks and biofabrication workflows that enable spatially programmed musculoskeletal tissue engineering, alongside advances in multi-material and gradient printing, interface-focused fabrication, and maturation platforms that meet vascular, mechanical, and structural demands. Speakers will also highlight how these seminal advances drive product fidelity, scalability, and adoption into clinical practice.` },
      { name: `Extracellular vesicles as nanomedicine for musculoskeletal regeneration and repair`, description: `This session will highlight emerging advances in extracellular vesicles (EVs) as next-generation nanomedicines for musculoskeletal tissue engineering and regenerative medicine. EVs derived from stem cells, immune cells, and engineered cell sources offer a powerful, cell-free therapeutic strategy to modulate inflammation, enhance angiogenesis, promote myogenesis and osteogenesis, and orchestrate tissue remodeling in musculoskeletal injuries and degenerative conditions. The session will feature cutting-edge approaches for EV isolation, bioengineering, and functionalization, as well as innovative delivery platforms including biomaterial scaffolds, hydrogels, injectable depots, and biofabricated constructs. Particular emphasis will be placed on EV-mediated immunomodulation, spatiotemporal control of regenerative signaling, and translational strategies for skeletal muscle, tendon/ligament, cartilage, and bone repair. The session will bring together leaders in EV biology, nanomedicine, and musculoskeletal tissue engineering to showcase mechanistic insights, preclinical advances, and translational pathways, fostering cross-disciplinary dialogue and accelerating clinical translation of EV-enabled regenerative therapies. The purpose of this session is to convene leaders in extracellular vesicle (EV) biology, nanomedicine, and musculoskeletal tissue engineering to define the state of the art and emerging directions for EV-enabled regenerative therapies. By integrating mechanistic insights with advances in EV engineering, delivery platforms, and translational models, the session aims to catalyze cross-disciplinary dialogue, identify key technical and biological challenges, and accelerate the clinical translation of EV-based nanomedicines for musculoskeletal repair. This forum will foster new collaborations, highlight best practices, and shape future research priorities in EV-driven immunomodulation and regenerative signaling across muscle, tendon/ligament, cartilage, and bone.` },
      { name: `Musculoskeletal microphysiological systems and new alternative models: Development to application`, description: `Microphysiological systems (MPS) and new alternative models (NAMs) are rapidly transforming musculoskeletal (MSK) research by enabling human-relevant, tissue-specific platforms that recapitulate complex biology with greater fidelity than traditional in vitro approaches. This session will highlight advances in MSK MPS/NAMs spanning bone, cartilage, skeletal muscle, tendon, and ligaments, with a focus on how these platforms are being leveraged to model aging, sex differences, regeneration, and rehabilitation. Speakers will discuss both model development and translational applications, including the use of well-characterized human tissue biobanks as cell/tissue sources. The session will bring together engineers, biologists, and translational researchers to foster interdisciplinary discussion around the scientific rigor, standardization, and translational potential of MSK NAMs.` },
      { name: `Precision recovery: Integrating machine learning and digital twin frameworks for orthopedic trauma and musculoskeletal regeneration`, description: `This session explores the transformative synergy between Machine Learning (ML) and Digital Twin (DT) development to revolutionize the treatment of complex orthopedic trauma. While traditional tissue engineering focuses on the biological building blocks, this session highlights how digital replicas continuously updated with patient-specific data can predict the non-linear healing trajectories of musculoskeletal tissues such as bone, cartilage, and ligaments. By integrating imaging data, biomechanical sensors, and predictive algorithms, we can move beyond the one-size-fits-all bioscaffolds toward dynamic, personalized therapeutic interventions that adapt to the patient's unique physiological environment. Presentations will highlight cutting-edge research into automated image segmentation, neural networks for tissue mechanobiology, and the development of virtual patient models for surgical planning. This session serves as a collaborative platform for bioengineers, data scientists, and orthopedic surgeons to discuss how we can standardize digital twin architectures to accelerate the clinical translation of regenerative therapies.` },
    ],
  },
  {
    title: `Neural & Spine`,
    subtopics: [
      { name: `Strategies for regeneration of the nervous system`, description: `Regenerating the nervous system remains one of the most significant challenges in biomedical science and engineering. This session will explore state-of-the-art strategies for promoting neural regeneration in both the peripheral and central nervous systems. Topics will include biomaterial scaffolds, cell-based therapies, bioactive molecules, and combinatorial approaches that integrate biophysical and biochemical cues.  A keynote speaker will provide a broad perspective on the field’s challenges and emerging opportunities, followed by emerging research from junior investigators, including graduate students and postdoctoral fellows. The session will highlight innovative approaches aimed at enhancing neural regeneration, improving functional recovery, and advancing translational strategies.` },
      { name: `Tissue engineering models of the nervous system`, description: `Tissue-engineered models of the nervous system are critical for understanding neurodevelopment, disease mechanisms, and therapeutic interventions. This session will cover cutting-edge advancements in neural tissue engineering, including biomimetic scaffold design, bioprinted neural networks, organoid models, and microphysiological systems (MPS).  The keynote speaker will discuss recent breakthroughs in modeling nervous system function and pathology using engineered platforms. Following this, emerging researchers will present innovative studies that utilize engineered neural tissues for applications such as neurodevelopmental modeling, neurodegenerative disease research, and drug screening.` },
    ],
  },
  {
    title: `Ophthalmologic`,
    subtopics: [
      { name: `Tissue engineering strategies in ophthalmology (general session)`, description: `Perception of a formed image is highly influenced by transparency of the ocular surface, refractive power of the cornea and lens, light detecting ability of the retina, and neural connectivity with the brain. Injury or disruption of ocular structures within the light path (i.e., ocular surface, cornea, lens, vitreous body, and neural retina) often have a profound impact on vision and quality of life. In this session, we will explore novel tissue engineering-based strategies used to evaluate disease pathology, test novel therapeutics, and rebuild damaged ocular tissues. By integrating advanced biomaterials, biofabrication, 3D printing, genome editing, and stem cell strategies, this session will address the critical need for tissue engineering solutions in ophthalmology.` },
    ],
  },
  {
    title: `Respiratory, Urologic & Gastrointestinal`,
    subtopics: [
      { name: `Respiratory, Urologic & Gastrointestinal TERM (general session)`, description: `General session on Respiratory, Urologic & Gastrointestinal TERM` },
      { name: `In silico advances in airway, gastroesophageal, and urogenital regeneration`, description: `This session will highlight emerging computational and lab on a chip technologies that are driving new insights and therapeutic strategies for airway, gastroesophageal, and urogenital regeneration. These organ systems share core structural and functional features: large tubular architectures exposed to fluid flow, complex mechanical loading, and abrupt environmental interfaces that shape transport and barrier function. Because of these shared constraints, innovations in one system often inform approaches in others. We will spotlight recent advances in benchtop microphysiological models, organ on a chip platforms, and computational models that capture flow, mechanics, and/or tissue remodeling in these interface organs. Discussions will emphasize unifying design principles, cross system lessons that can accelerate regenerative solutions and methodologies for verification and validation of these modeling strategies.` },
      { name: `Tissue engineering and regenerative medicine for upper airway restoration`, description: `Upper airway tissue engineering has evolved from voice and airway research in parallel with mainstream tissue engineering, yet these communities have had limited exchange. This session aims to bridge that gap by bringing upper airway regenerative medicine to the attention of the broader TERM community. We will address two interconnected domains: (1) vocal fold regeneration using injectable biomaterials and decellularized extracellular matrices and (2) airway reconstruction for subglottic stenosis and tracheal defects through tissue-engineered scaffolds.   The session will feature advances in biomaterial development, computational modeling for predicting tissue remodeling, and organ-on-chip platforms for preclinical testing. By integrating perspectives from bioengineers, cell biologists, and head and neck surgeons, we anticipate that both upper airway specialists and the broader TERM community will benefit from this exchange of ideas and methods.    Qualifications of Session Chairs  Qualifications:  Dr. Li-Jessen holds the Canada Research Chair in Personalized Medicine of Upper Airway Health and leads an interdisciplinary research program spanning computational medicine, tissue engineering, and digital health for laryngeal and upper airway diseases. Her expertise includes decellularized extracellular matrix hydrogels, agent-based computer modeling for tissue regeneration, and organ-on-chip systems for upper airway applications.    Dr. Kim is a surgeon–scientist specializing in tissue engineering and regenerative medicine of the upper airway, with a particular emphasis on tracheal and laryngeal regeneration. His research is distinguished by the development and translational application of tonsil-derived stem cells (TDSCs) as a novel, clinically accessible cell source for airway regeneration. By integrating stem cell biology, biomaterials, and clinically relevant animal models, his work aims to restore functional airway tissues and bridge the gap between bench-top discoveries and surgical application in regenerative medicine.` },
      { name: `Tissue engineering and regenerative medicine in otolaryngology: Historical perspectives and current challenges`, description: `Otolaryngology encompasses organ systems responsible for some of the most essential human functions - hearing, balance, olfaction, respiration, phonation, and swallowing. These capabilities depend on highly specialized tissues with intricate structural organization, precise neural integration, and finely tuned biomechanical properties. Because of this complexity, tissue engineering and regenerative medicine have long been viewed as promising yet particularly challenging avenues for therapeutic innovation in the field.  This session will provide a comprehensive, tissue‑specific overview of regenerative and bioengineering efforts across otology, rhinology, laryngology, and head and neck surgery. It will begin with a historical perspective on early regenerative attempts, examining the scientific and translational barriers that limited their success. Building on these foundational lessons, the session will highlight current advances in stem cell biology, biomaterials, and bioengineering that are reshaping strategies for restoring function in sensory organs and aerodigestive tissues.  Topics will include:  •	Outer and middle ear: tympanic membrane regeneration, ossicular chain reconstruction, auricular cartilage engineering  •	Inner ear: hair cell regeneration, spiral ganglion neuron repair, cochlear synapse restoration  •	Nose and paranasal sinuses: nasal cartilage engineering, mucosal regeneration, olfactory epithelium repair, sinus bone regeneration  •	Larynx and trachea: vocal fold tissue engineering, laryngeal cartilage regeneration, tracheal reconstruction, airway mucosal repair  •	Oral cavity and oropharynx: oral mucosa regeneration, tongue muscle restoration, soft palate reconstruction  •	Head and neck: salivary gland regeneration, mandibular and maxillary bone reconstruction, facial nerve regeneration  By integrating historical insights with emerging technologies, this session will identify the key biological, engineering, and translational challenges that continue to impede progress. It will also outline future directions aimed at achieving durable, functional regeneration across the diverse tissues of otolaryngology.` },
    ],
  },
  {
    title: `Scaffolds, Matrices, and Biomaterials`,
    subtopics: [
      { name: `Scaffolds, Matrices, and Biomaterials in TERM (general session)`, description: `General session on Scaffolds, Matrices, and Biomaterials in TERM` },
      { name: `Advanced biomaterials for controlled drug release and immune modulation`, description: `Biomaterials are extensively employed to deliver drugs, proteins, and nucleic acids to enhance tissue regeneration, modulate immune responses, and treat a wide range of diseases. By tailoring the physical and chemical properties of these materials, it is possible to precisely control release kinetics, delivery efficiency, and host immune interactions, thereby enabling improved tissue repair and more effective therapeutic outcomes.    This session will convene researchers and experts from diverse fields to discuss cutting-edge advances in biomaterials-enabled drug delivery, gene therapy, and immunomodulation. The knowledge shared will help drive the development of next-generation biomaterial-based therapies, with the goal of improving patient care and supporting future biomedical innovations. Abstracts and presentations may address topics such as the use of advanced biomaterials for immunomodulation, targeted and on-demand delivery of drugs and genes, tuning biomaterial properties to enhance delivery efficacy, and the impact of biomaterial characteristics on intracellular trafficking and/or transport of drugs, cytokines, metabolites, or nucleic acids.` },
      { name: `Advances in decellularization and recellularization of complex tissues`, description: `Decellularization and recellularization techniques have emerged as powerful tools in tissue engineering, enabling the creation of complex functional tissues for transplantation and regenerative medicine applications. This session aims to explore the latest advancements and breakthroughs in decellularization and recellularization strategies, focusing on their application in the development of complex tissue constructs.       Abstracts/presentations can include novel decellularization techniques and advances in recellularization strategies: with focus on techniques for cell seeding, cell distribution, and cell viability maintenance within the complex three-dimensional (3D) ECM architecture, including perfusion-based systems, bioink-based approaches, and organoid-based recellularization.     Abstracts/presentations can also include tissue-specific challenges and successes focusing on immunogenicity, biocompatibility, and host integration of decellularized and recellularized scaffolds.` },
      { name: `Development of stimuli-responsive implants for musculoskeletal tissue engineering`, description: `This session will highlight emerging advances in the design and development of stimuli-responsive implants for musculoskeletal tissue engineering and regenerative medicine. These next-generation systems integrate smart biomaterials, electroactive and mechanoresponsive constructs, and biofabricated platforms that dynamically interact with the injury microenvironment. By leveraging spatiotemporal control of biochemical, mechanical, and electrical cues, such implants aim to modulate inflammation, mitigate fibrosis, promote vascularization, and drive functional tissue regeneration across bone, cartilage, tendon, and skeletal muscle. The session will feature cutting-edge innovations in responsive polymers, bioactive composites, electroconductive scaffolds, and 3D-printed/bioprinted regenerative constructs. Particular emphasis will be placed on immunomodulatory strategies, adaptive regenerative signaling, and integration with external stimulation to restore functional musculoskeletal performance. Leaders in biomaterials science, regenerative bioengineering, and translational musculoskeletal research will share mechanistic insights, preclinical findings, and clinical perspectives to accelerate the development of intelligent implantable systems for trauma and degenerative conditions.` },
      { name: `Engineering dynamic microenvironments to direct cell signaling, stem cell fate, and function`, description: `Cells in multicellular tissues communicate both with neighboring cells and with the surrounding extracellular matrix (ECM) through biochemical, mechanical, electrical, and spatial cues. Recreating physiological tissue architecture and function therefore requires bioengineered microenvironments whose properties can be precisely tuned in space and time to regulate cell signaling and direct cell fate. This session will bring together researchers developing ECM-inspired biomaterials and engineered culture systems that actively control the biochemical, biophysical, and cellular microenvironment to guide stem cell fate and broader tissue function. Topics will include, but are not limited to, dynamic modulation of scaffold properties such as stiffness, viscoelasticity, and degradation; controlled presentation or delivery of soluble factors; engineered cell-cell interactions through co-culture systems; and external stimulation strategies including optical, magnetic, chemical, mechanical, and electrical cues. By integrating biomaterials engineering with cell and stem cell biology, this session aims to highlight generalizable strategies for reproducible control of cell behavior, tissue organization, and regenerative function.` },
      { name: `Engineering immunomodulatory therapies for regenerative medicine`, description: `The immune system is a central regulator of tissue repair, regeneration, and fibrosis. This session will explore how the rational design of cells, drugs, biologics, and/or biomaterials can be leveraged to direct immune cell behavior and, in turn, shape regenerative outcomes. Approaches include (but are not limited to) engineered tissue scaffolds, nanoparticles, extracellular matrices, devices, biologics, and cells that can modulate the innate and/or adaptive immune system and immune–stem/progenitor cell crosstalk to promote pro-regenerative microenvironments.` },
    ],
  },
  {
    title: `Skin, Wound Healing, and Inflammation`,
    subtopics: [
      { name: `TERM for Skin, Wound Healing, and Inflammation (general session)`, description: `General session on TERM for Skin, Wound Healing, and Inflammation` },
      { name: `Biophysical and biomaterial strategies to modulate wound healing`, description: `Wound healing is a highly dynamic and multifaceted process governed by tightly coupled cellular, molecular, and mechanical cues. Beyond its central role in skin repair and chronic wound management, wound healing underpins the success of tissue engineering and regenerative medicine across diverse tissues, including the cornea and other organ systems where regeneration relies on coordinated healing responses. This session will showcase cutting-edge biophysical and biomaterial strategies to modulate the wound microenvironment and direct regenerative outcomes. Emphasis will be placed on mechanobiology, including mechanotransduction, force-mediated cell–matrix interactions, and the critical role of material properties such as stiffness, viscoelasticity, and topography in regulating cell behavior. Topics will span scaffold-guided regeneration, dynamic and responsive biomaterials, and translational approaches designed to enhance healing, minimize fibrosis, and restore tissue function in both acute and chronic injury contexts.` },
    ],
  },
  {
    title: `Stem Cells & Cell Therapies & Developmental Biology and Cell Signaling`,
    subtopics: [
      { name: `Stem Cells & Cell Therapies & Developmental Biology and Cell Signaling (general session)`, description: `General session on Stem Cells & Cell Therapies & Developmental Biology and Cell Signaling` },
      { name: `Harnessing the power of microgravity to accelerate breakthroughs in regenerative medicine`, description: `Progress continues toward the development of disease models, stem cell manufacturing and tissue engineered products in microgravity that will change the paradigm of regenerative medicine. This session will discuss how NASA/Private/Commercial Astronaut Missions to the International Space Station are providing increased opportunities for access to microgravity that are accelerating the pace of development for biomedical applications and share a view of what the future of in-space biomanufacturing will look like.   Microgravity has the potential to create a new definition of global for research and biomanufacturing, that includes low-Earth orbit (LEO) 250 miles above the Earth. This session will provide participants with an overview of ongoing biomedical initiatives shaping the next frontier for regenerative medicine and biomanufacturing that stand to provide significant global and societal benefits.` },
      { name: `microRNA-guided stem cell differentiation in regeneration and disease`, description: `MicroRNAs (miRNAs) are critical post-transcriptional regulators of gene expression that play central roles in stem cell self-renewal, differentiation, and phenotypic stability. This session will examine miRNA-guided cell fate decisions in the context of regeneration and disease. While miRNA delivery has emerged as a promising strategy to promote tissue regeneration and functional repair, increasing evidence highlights a narrow regulatory window in which regenerative signaling can shift toward pathological or oncogenic outcomes if improperly controlled. The session will focus on how miRNA dosage, timing, delivery modality, and microenvironmental context govern therapeutic efficacy and safety. It will explore emerging approaches to precisely regulate miRNA activity, including engineered delivery systems and microenvironmental control strategies. By integrating insights from stem cell biology, RNA regulation, and tissue engineering, this session aims to define principles for leveraging miRNAs to enable robust regeneration while minimizing pathological risk.` },
      { name: `Stem cell signaling in tissue engineering and regenerative medicine: From in vitro to in vivo`, description: `This session will highlight the central role of stem cells and cell signaling pathways in advancing tissue engineering and regenerative medicine across multiple organ systems. Emphasis will be placed on both in vitro and in vivo applications of stem cells, including endogenous progenitors, pluripotent stem cells, and genetically engineered cell populations, with a focus on how biochemical, mechanical, and spatial signaling cues regulate stem cell fate, function, and tissue organization. Presentations will feature recent advances in 3D tissue models, organoids, and engineered microenvironments that enable precise control of stem cell differentiation, maturation, and cell–cell communication. The session will also address the translation of signaling insights from in vitro systems to ex vivo and in vivo disease and regeneration models, highlighting strategies for stem cell delivery, integration, and long-term functional outcomes in diverse tissues. In addition, discussions may include emerging technologies that shape stem cell signaling and therapeutic potential, such as CRISPR-based genome and epigenome editing, bioprinting, immune engineering, and immuno-cloaking approaches, alongside considerations of safety, ethics, and regulatory pathways. Together, this session will bridge fundamental stem cell biology and signaling mechanisms with translational tissue engineering applications, providing a platform for interdisciplinary exchange within the TERMIS community.` },
    ],
  },
  {
    title: `Special Topic: Sex and Lifespan Biology in Tissue Engineering and Regenerative Medicine`,
    subtopics: [
      { name: `Advancing women’s health through inclusive innovation`, description: `This session will address the dual challenge of supporting female scientists and engineers in TERM while addressing the historical gaps in women’s health research. This session will highlight the contributions of women researchers who are driving innovation while navigating the unique challenges of being women in academia. The session will highlight topics related to maternal health, endometriosis, pelvic floor repair, and sex-based differences in regenerative responses. This session is being organized by the TERMIS Community Access & Engagement (CAE) Committee.` },
      { name: `Fetal and pediatric tissue engineering and regenerative medicine`, description: `Children stand to benefit greatly from tissue-engineered and regenerative medicine therapies for injury and disease, yet they are arguably underserved by current research efforts. Development of therapies is challenged by the dynamic nature of their tissues, the heterogeneity of congenital and acquired diseases, and hurdles of pediatric translational medicine. Customized solutions are often needed for small patient populations. These challenges have driven the field toward innovative materials, dynamic scaffolds, and new therapeutic paradigms for growing patients. This session will present a broad range of tissue engineering and regenerative medicine efforts across fetal and pediatric tissues and organs. The keynote will feature clinical implementation of these technologies and discuss key considerations for translation and improving pediatric patient outcomes.` },
      { name: `Sex hormone influence on tissue engineering and regenerative medicine`, description: `Since NIH implemented the Sex as a Biological Variable (SABV) policy, research has progressed from describing sex-biased outcomes to defining hormone-driven mechanisms that regulate tissue biology. Multi-omics, single-cell analyses, and engineered microphysiological systems show that estrogens, progestogens, and androgens dynamically control proliferation, metabolism, differentiation, and matrix remodeling across organ systems. Hormonal transitions during puberty, pregnancy, peri-menopause, and aging substantially alter tissue homeostasis and regenerative capacity. Tissue-engineered platforms uniquely enable precise control of cyclic hormone exposure and mechanical loading, revealing sex-specific differences in stem cell fate, extracellular matrix organization, and injury response. Together, these advances establish sex hormones as fundamental regulators of tissue physiology and highlight that failure to model hormonal state may obscure key mechanisms of disease and repair. This session will feature cutting-edge engineered systems used to dissect sex- and hormone-mediated regulation of tissue repair and regeneration, emphasizing mechanistic insight and translational impact across the lifespan.` },
    ],
  },
  {
    title: `Special Topic: Computer Modeling & Artificial Intelligence Applications in TERM`,
    subtopics: [
      { name: `Complex data sets and AI applications in TERM`, description: `Artificial intelligence (AI) is rapidly transforming tissue engineering and regenerative medicine (TERM) by enabling deeper insights into cellular behavior, tissue dynamics, and regenerative processes while accelerating the development of personalized TERM efforts and future therapies. The growing availability of complex data sets including multi-omics profiles, advanced imaging, and functional characterization data from healthy, diseased, and engineered tissues offers unprecedented opportunities to understand biological mechanisms at cellular and molecular scales. However, extracting meaningful knowledge from these high-dimensional data requires sophisticated AI and machine learning approaches. This symposium will highlight state-of-the-art AI-driven methods for analyzing large, multimodal data sets, including AI-powered imaging, single-cell analytics, and data-driven modeling frameworks. Presentations will showcase how these techniques enable biomarker discovery, reveal patterns, predict affected biological pathways, and provide functional insights into tissue regeneration and repair. By integrating imaging, computational, and experimental strategies, this session aims to demonstrate how AI can uncover mechanisms underlying impaired regeneration, advance tissue engineering strategies, and improve therapeutic outcomes. Together, these contributions will illustrate how leveraging complex data sets through AI is reshaping TERM research, driving innovation in regenerative therapies, and opening new dimensions in cellular and tissue analysis.` },
      { name: `Computational methods for biomaterial design`, description: `Computational modeling and machine learning can enhance our ability to design and evaluate biomaterials for a variety of tissue engineering applications. This session will explore computational approaches and tools for designing biomaterials for tissue engineering, evaluating complex data from in vitro and in vivo studies, and predicting biomaterial performance in different microenvironments. Examples of these may include fluid mechanics and bio-transport models of drug/protein delivery, models of protein-protein and protein-material interactions, statistical modeling for biomaterial optimization, machine learning for biomaterial design and analysis, and bioinformatics-based platforms for analyzing complex data, including RNA sequencing and other -omics approaches.` },
    ],
  },
  {
    title: `Special Topic : Nanocarriers and Novel Technologies Applications to TERM`,
    subtopics: [
      { name: `Engineering the code: Advances in lipid nanoparticle-mediated CRISPR delivery for tissue regeneration`, description: `The clinical success of mRNA vaccines has brought lipid nanoparticles (LNPs) to the forefront of therapeutic delivery, yet their application in tissue engineering and regenerative medicine remains an emerging frontier. This session focuses on the intersection of non-viral gene delivery and CRISPR-based gene editing to overcome complex tissue barriers and drive regenerative outcomes. We will explore delivery strategies designed to penetrate dense extracellular matrices, the integration of gene editing tools with biomaterial scaffolds, and methods to achieve precise spatiotemporal control over tissue regeneration. By bringing together experts in biomaterials, nucleic acid and protein delivery, and tissue engineers, this session aims to define design principles of in vivo tissue gene editing for regenerative medicine.` },
      { name: `Gene editing for tissue engineering and regenerative medicine`, description: `Tissue loss from trauma, disease, and congenital defects represents a major clinical burden, with current regenerative strategies often failing to restore full tissue functionality. Gene editing technologies offer transformative potential to enhance tissue repair by enabling precise cellular reprogramming, functional tissue repair, and accurate disease models. Despite advances in CRISPR technologies and recent clinical success, implementation in tissue engineering and regenerative medicine (TERM) remains limited.  This session will showcase innovative strategies that bridge this gap. Key topics include:  precision editing to direct cell phenotype and matrix deposition, integrating gene editing with  biomaterials for in vivo gene editing, engineering stimuli-responsive cells for enhanced repair,  gene-edited disease modeling, and approaches addressing vascularization and  immunomodulation.  This session will highlight how synthetic biology principles are enabling rational design of gene-edited tissues with enhanced functionality, accelerating the development of next-generation  regenerative therapies.` },
      { name: `Nanotechnology-driven strategies for inflammatory modulation in TERM applications`, description: `Chronic or dysregulated inflammation is a major barrier to successful TERM therapies, as it can delay healing, impair tissue regeneration, compromise biomaterial integration, and drive long-term tissue degeneration. This session will highlight recent advances in nanotechnology-driven and biomaterial-based strategies used to modulate inflammatory responses and enhance tissue regeneration. Topics will include smart, multifunctional, and immunomodulatory nanocarriers engineered to interact with the immune system and improve therapeutic efficacy. Particular emphasis will be placed on clinically relevant strategies, including stimuli-responsive and on-demand systems, AI-assisted and computationally guided material design, and precision strategies tailored to tissue- and patient-specific inflammatory environments. By bridging fundamental immunoengineering research with preclinical and clinical applications, this session will showcase how immunomodulatory nanotechnologies can improve regenerative outcomes across TERM applications.` },
    ],
  },
  {
    title: `Special Topic: Extracellular Vesicles`,
    subtopics: [
      { name: `CRISPR-Cas9–enabled drug delivery strategies for wound healing and tissue regeneration`, description: `CRISPR-Cas9–based genome editing has emerged as a central driver of next-generation regenerative therapies, with growing interest in its application to tissue repair and wound healing. Despite its molecular precision, effective clinical translation of CRISPR-Cas9 remains highly dependent on advanced drug delivery strategies capable of overcoming biological barriers in complex wound microenvironments. This session will highlight recent advances in CRISPR-Cas9–enabled delivery platforms, including lipid nanoparticles, polymeric nanocarriers, and biomaterial-based systems, that enable localized, efficient, and temporally controlled gene modulation. Emphasis will be placed on delivery strategies designed to regulate key regenerative processes such as inflammation resolution, angiogenesis, and extracellular matrix remodeling in acute and chronic wounds. By integrating perspectives from genome engineering, delivery science, and wound biology, this session aims to define emerging opportunities, translational challenges, and future directions for CRISPR-Cas9 therapeutics within regenerative medicine, aligning with the core scientific themes of Tissue Engineering and Regenerative Medicine International Society (TERMIS-AM) 2026.` },
      { name: `Extracellular vesicles for regenerative medicine, drug delivery, and cell-free therapies`, description: `Extracellular vesicles (EVs) are naturally produced, lipid-bound nanoparticles that mediate intercellular communication by transferring bioactive cargo—including proteins, lipids, and nucleic acids—between cells. Over the past decade, EVs have transformed our understanding of cell signaling, disease mechanisms, and regenerative processes, influencing phenomena such as immune modulation, cancer progression, aging, and wound repair. In tissue engineering and regenerative medicine, EVs are emerging as powerful cell-free therapeutic platforms. Compared with traditional cell-based strategies, EV-based approaches offer advantages including reduced immunogenicity, improved biocompatibility, and strong translational potential. EVs derived from stem cells and other sources can regulate key regenerative processes such as cell proliferation, differentiation, extracellular matrix remodeling, and tissue repair through paracrine signaling. Beyond regenerative applications, EVs are also being explored as non-invasive biomarkers and as targeted drug delivery vehicles for precision medicine and gene therapy. Advances in EV engineering—including cargo loading, surface modification, and integration with biomaterial systems—are further expanding their therapeutic capabilities. This session will highlight recent advances in EV biology and applications in regenerative medicine, including emerging discoveries in matrix-bound nanovesicles (MBVs) and innovations that are enabling next-generation EV-based therapies.` },
    ],
  },
  {
    title: `Special Topics: TERMIS & The Histochemical Society`,
    subtopics: [
      { name: `The extracellular matrix: Target and tool in disease and repair`, description: `This joint session aims to foster cross‑disciplinary dialogue and innovation within the TERMIS and Histochemical Society communities.` },
    ],
  },
];
